    28|  const enabled = redisUrl !== null && process.env.IVX_REDIS_ADAPTER_ENABLED === 'true';
    29|  const instanceId = `${process.env.HOST ?? 'localhost'}-${process.env.PORT ?? '3000'}-${Date.now()}`;
    30|  return {
