    96|export function validateFileUpload(
    97|  filename: string,
    98|  mimeType: string,
    99|  size: number,
   100|): FileValidationResult {
   101|  const errors: string[] = [];
   102|
   103|  // Check file size
   104|  if (size > MAX_FILE_SIZE) {
   105|    errors.push(`File size ${size} exceeds maximum ${MAX_FILE_SIZE} bytes (50 MB)`);
   106|  }
   107|
   108|  // Check MIME type
   109|  if (!ALLOWED_MIME_TYPES.has(mimeType)) {
   110|    errors.push(`MIME type "${mimeType}" is not allowed`);
   111|  }
   112|
   113|  // Check extension
   114|  const ext = filename.split('.').pop()?.toLowerCase() ?? '';
   115|  if (DANGEROUS_EXTENSIONS.has(ext)) {
   116|    errors.push(`File extension ".${ext}" is not allowed`);
   117|  }
   118|
   119|  // Sanitize filename — remove path traversal attempts
   120|  const sanitizedFilename = filename
   121|    .replace(/\.\./g, '')
   122|    .replace(/\//g, '')
   123|    .replace(/\\/g, '')
   124|    .replace(/\x00/g, '')
   125|    .slice(0, 255);
   126|
   127|  // Detect actual type from extension
   128|  const detectedType = ext || 'unknown';
   129|
   130|  return {
   131|    valid: errors.length === 0,
   132|    errors,
   133|    sanitizedFilename,
   134|    detectedType,
   135|  };
